         }
     }
     $person->configure(array(
         'name'=>'Eko'
     ));
     $person->getConfig('name'); // return 'Eko'

Any class can use proxy to make operation to database then proxy forward process onto \Roulette\Roulette\Adapter.
One proxy proxy for one table, to operate CRUD in another table use better to use another table.
Any custom operation can made with method `query`.

     // dont forget to set the adapter first, only once
     // eg, use CI3 framework
     Proxy::tunnel(new \Roulette\proxies\CI3\Proxy($this->db));

Proxy can be used for CRUD in SQL notation (SELECT, INSERT, UPDATE, DELETE)

     // INSERT operation using proxy
     Proxy::insert('employees', array(
         'name'=>'me', 'job'=>'programmer'
     ));

     // UPDATE operation using proxy
     Proxy::update('employees', array(
         'name'=>'me' // where name is `me`
     ), array(
         'job'=>'developer' // set job = `developer`
     ));

     // SELECT operation using proxy
     Proxy::select('employees', array(
         'limit'=> 3,
         'filters' => array( 'job'=>'developer' )
     )); // will return array of record from database

     // DELETE operation using proxy
     Proxy::delete('employees', array(
         'name'=>'me' // where name is `me`
     ));

Example:

     // #using fields
     // fields can be writen in string or array (numeric or associative)
     Proxy::select(array(
         'table' => 'users',
        'fields' => array('name','email') // it can be writen as string as well, eg: 'name, email'
     ));
     // if writen in string
     Proxy::select(array(
         'table' => 'users',
        'fields' => 'name,email'
     ));
     // or using array as alias
     Proxy::select(array(
         'table' => 'users',
        'fields' => array('name'=>'Name') // will same as 'select `name` as `Name`'
     ));

     // #using filters
     // filters is like fields, could be writen in string or array
     Proxy::select(array(
         'table' => 'users',
         'filters' => 'name = `me`'
     ));
     // or
     Proxy::select(array(
         'table' => 'users',
         'filters' => array('name'=>'me')
     ));
     // and easy to use multi filters
     // if you are familiar with CI where condition style, it will be easy
     Proxy::select(array(
         'table' => 'users'
         'filters' => array('email like'=>'%@gmail.com', 'ocupation IS NOT NULL'=>null, 'age >'=>5)
     ));

     // #using sorter
     // sorter can be writen in string or array too
     Proxy::select(array(
         'table' => 'users'
         'sorter' => 'name' // will be sort by name asc
     ));
     // or
     Proxy::select(array(
         'table' => 'users'
         'sorter' => 'name desc' // will be sort by name desc
     ));
     // or
     Proxy::select(array(
         'table' => 'users'
         'sorter' => array('name') // will be sort by name asc
     ));
     // or
     Proxy::select(array(
         'table' => 'users'
         'sorter' => array('name'=>'desc') // will be sort by name desc
     ));
     // or use multiple sort
     Proxy::select(array(
         'table' => 'users'
         'sorter' => array('name', 'age'=>'desc') // will be sort by name asc and sort by age desc
     ));

     // #using limmit and sort
     Proxy::select(array(
         'table' => 'users'
         'limit' => 10 // default is null, mean no limit
     ));
     // or
     Proxy::select(array(
         'table' => 'users'
         'limit' => 10,
         'start' => 5  // default is 0
     ));

     // #using result_array
     Proxy::select(array(
         'table' => 'users'
         'result_array' => false // each record will be return as object instead of array, default result_array is true
     ));

Example:
     class Person extends \Roulette\Base
     {
         protected $name = null;
         function __construct($config){
             function __construct($config)
         }
     }
     $person->configure(array(
         'name'=>'Eko'
     ));
     $person->getConfig('name'); // return 'Eko'

$person = new Person(array(
         'listener'=>array(
             'sing'=>function(){
                 echo "la la la laa la ~";
             }
         )
     ));

     // easy to trigger it
     $person->trigger('sing'); // will echo 'la la la laa la ~';

     // easy to add listener or remove it
     $singing = function(){
         echo "you are the one that i loved ~";
     }
     $person->on('sing', $singing);
     $person->removeListener('sing', $singing);

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing');
         }
     }

     $person = new Person();
     $person->trigger('sing'); // will executed any `sing` listeners

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
         }
     }

     $person = new Person();
     $person->addEvent('sing'); // return array('sing')
     $person->addEvent(array(
         'run','dance','swim'
     ));
     // return array('run','swim'), because event `dance` is already registered

Disabled event mean exist

     Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
         }
     }

     $person = new Person();
     $person->hasEvent('sing'); // return false;
     // add a `sing` event
     $person->addEvent('sing');
     $person->hasEvent('sing'); // return true;

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance');
         }
     }

     $person = new Person(array(
         'listeners'=>array(
             'sing'=>function() use($person){
                 echo "i would'n sing anymore if the event removed";
             }
         )
     ));
     $person->trigger('sing');
     // echo: i would'n sing anymore if the event removed

     $person->removeEvent('sing');
     // person no longer can 'sing'
     $person->trigger('sing');
     // do nothing

     // using array
     $person->removeEvent(array(
         'event1', 'event2'
     ));

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance');
         }
     }

     $person->enableEvents(false); // disable all event capturing
     $person->trigger('sing');
     // do nothing

     // enable all event capturing
     // it doesnt affect from disabled event
     // only change the capturing status
     $person->enableEvents(true);
     $person->trigger('sing');
     // doing 'sing' function

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance');
         }
     }

     $person = new Person(array(
         'listeners'=>array(
             'sing'=>function() use($person){
                 echo "i would'n sing anymore if the event removed";
             }
         )
     ))

     $person->enableEvent('sing',false); // person no longer can 'sing' till the event enabled
     $person->trigger('sing');
     // do nothing

     $person->enableEvent('sing',true); // now person can sing anymore
     $person->trigger('sing');
     // echo: i would'n sing anymore if the event removed

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing');
         }
     }

     $person->enableEvent('sing');
     $person->eventEnabled('sing'); // return: true
     $person->eventEnabled('walk'); // return: false, because event `walk` doesnt exist

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance');
         }
     }

     $person = new Person(array(
         'listeners'=>array(
             'sing'=>function() use($person){
                 echo "i would'n sing anymore if the event removed";
             }
         )
     ))

     $person->disableEvent('sing'); // person no longer can 'sing' till the event enabled
     $person->trigger('sing');
     // do nothing

     $person->disableEvent('sing',false); // now person can sing anymore
     $person->trigger('sing');
     // echo: i would'n sing anymore if the event removed

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing');
         }
     }

     $person->disableEvent('sing',true);
     $person->eventDisabled('sing'); // return: true
     $person->eventDisabled('walk'); // return: true, because event `walk` doesnt exist

Example:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
         }
         function lazy(){
             echo 'i dont want do anything at this time'
         }
     }
     $person = new Person();
     $person->addListener('walk', $person->lazy);
     $person->addListener(array(
         'walk' => $person->lazy,
         'dance' => $person->lazy
     ));

Examples:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance','walk');
         }
         function lazy(){
             echo 'i dont want do anything at this time'
         }
     }

     $person = new Person();
     $person->on('sing',$peson->lazy);
     $person->on('dance',$peson->lazy);
     $person->on('walk',$peson->lazy);

     $person->remove_listner('sing',$person->lazy);
     // person will not 'lazy' when 'sing'
     // person still 'lazy' if 'walk' or 'dance'

     $person->remove_listner(array('walk'),$person->lazy);
     // person will not 'lazy' when 'walk'
     // person still 'lazy' in 'dance'

     $person->removeListener(null, $person->lazy); // will remove any listener on each events that have $person->lazy function
     // person will not 'lazy' anymore

Examples:
     class Person extends \Roulette\Base
     {
         function __construct($config){
             function __construct($config)
             $this->addEvent('sing','dance','walk');
         }
     }

     $person = new Person();
     $person->on('sing',$peson->lazy);
     $person->clearListener('sing');
     // sing listeners are removed

     $person->clearListener();
     // person have no any single listener on each event
